            arr[i - start] = String.valueOf(i);
        }
    }

    return arr;   
}

public boolean canBalance(int[] nums)
{
    int j =nums.length-2;
    int i =1;
    int front = nums[0];
    int tail = nums[j+1];    
         while(j>i)
          {
         	if( front < tail)
    	 	{
        		front += nums[i];
                i++;
         	}
         	else
    		{
            	tail+=nums[j];
                j--;
        	}
   		 }
    return front==tail;
}

