public int sum67(int[] nums)
{
    int sum = 0;
    while (int i < nums.length)
    {
        if (nums[i] == 6)
        {
            for (int x = 1; x < nums.length - i; x++)
            {
                if (nums[i + x] == 7)
                {
                    break;
                }
                else
                {
                    continue;
                }
            }
            i = i + x;
        }
        else
        {
            sum = sum + nums[i];
            i = i + 1;
        }
    }
    return sum;
}

