public int[] tenRun(int[] nums)
{
    int[] ten = new int[nums.length];
    boolean isTen = false;
    private int tenMult;

    for (int i = 0; i < nums.length; i++)
    {
        if (nums[i] % 10 == 0 && nums[i] != tenMult)
        {
            isTen = true;
            tenMult = nums[i];
            ten[i] = nums[i];
        }

        else if (isTen)
        {
            ten[i] = tenMult;
        }

        else
        {
            ten[i] = nums[i];
        }
    }
 	return ten;
}

public String zipZap(String str)
{
   int leg = str.length();
   int l = leg - 2;
   int s = 0;
   char c;
   StringBuilder build = new StringBuilder(leg);
    while ( s < leg)
    {
        c = str.charAt(s);
        if (c == 'z' && s < l && str.charAt(s + 2) == 'p')
        {
            build.append("zp");
            s += 3;
        }
        else 
        {
            build.append(c);
                s++;
        }


    }
    return build.toString();
}

