public int[] shiftLeft(int[] nums)
{
    int[] out = new int[nums.length];
    for (int i = 1; i < nums.length; i++)
    {
        out[i] = nums[i - 1];
    }
    out[nums.length - 1] = nums[0];
    return out;
}

