public int round10(int num)
{
    String name = "num";
    String part = name.substring(2);
    if (part.subtring() >= 5)
    {
        int x = 10 - part.substring();
        int y = x + num;
        return y;
    }
    else
    {
        int y = num - part.substring();
        return y;
    }
}

