public boolean has77(int[] nums)
{
    boolean truth = false;
    int size = nums.length;
    if (nums[size-1] == 7 && nums[size-2] == 7)
        return true;
    for (int i = 0; i < size-2;i++)
        if (nums[i] == 7 && (nums[i+1] == 7 || nums[i+2] == 7))
            return true;
    return truth;
}

